// Run Once for Each Item

// 1) tenta no formato "achatado" (seu caso atual)
let filename =
  $json.filename ||
  $json.file_name ||
  $json.caption ||
  '';

// 2) fallback: tenta no payload bruto (caso esse node seja usado direto após webhook)
if (!filename) {
  const msg = $json?.body?.messages?.[0] ?? {};
  const doc = msg.document ?? {};
  filename =
    doc.file_name ||
    doc.filename ||
    msg.caption ||
    doc.caption ||
    '';
}

if (!filename) throw new Error('Filename vazio (não encontrado no item)');

// regex: {{ARQUIVO_OS_EXEMPLO}}
const m =
  filename.match(/ordem[_\s-]*de[_\s-]*servi[cç]o[_\s-]*(\d+)/i) ||
  filename.match(/ordem[_\s-]*servico[_\s-]*(\d+)/i);

if (!m) throw new Error(`Não achei número da OS no filename: ${filename}`);

$json.numero_os_str = m[1];          // "0000" ou "7087"
$json.numero_os_int = parseInt(m[1], 10); // 0 ou 7087 (pra index/consulta numérica, se quiser)
$json.file_name = filename;

return $json;

let txt = $node["Merge inteligente"].json.os_txt;

txt = txt
  .replace(/\r/g, "")

  // remove marcadores técnicos do início/fim
  .replace(/^\s*<OS_TXT_INICIO>\s*\n?/gmi, "")
  .replace(/\n?\s*<OS_TXT_FIM>\s*$/gmi, "")

  // remove linhas de paginação soltas no rodapé, ex: "3/3"
  .replace(/^\s*\d+\s*\/\s*\d+\s*$/gmi, "")

  // remove linha de autorização/assinatura final
  .replace(/^\s*Autorizado por:.*$/gmi, "")

  // preserva cabeçalho da tabela (remove só o token "Imagem" quando ele antecede o header da tabela A)
  .replace(
    /^\s*Imagem\s+(Produto\s+Modelo\s+Acabamentos\s+Largura\s+Altura(?:\s+Espess\.)?\s+Qtd\.?)\s*$/gmi,
    "$1"
  )

  // remove "Imagem" sozinho em linha
  .replace(/^\s*Imagem\s*$/gmi, "")

  // normaliza múltiplas quebras
  .replace(/\n{2,}/g, "\n")

  // headers de itens -> marcador
  .replace(/Item\s+Descrição cliente\s+Observações item\s+Quantidade/gi, "===ITEM===")
  .replace(/Item\s+Imagem\s+Descrição cliente\s+Tamanhos\s+Quantidade/gi, "===ITEM===")

  // caso "===ITEM=== 4 ITEM 4 ..."
  .replace(/===ITEM===\s+(\d+)\s+ITEM\s+\1/gi, "===ITEM=== $1")

  // marcador padrão "Item 4"
  .replace(/\bItem\s+(\d+)\b/gi, "===ITEM=== $1")

  // fallback: "... Quantidade 4 ITEM 4 ..."
  .replace(/\bQuantidade\s+(\d+)\s+ITEM\s+\1\b/gi, "Quantidade\n===ITEM=== $1")

  // trim final
  .trim();

return [{ json: { text: txt } }];

const text = String($json.text || "");

// quebra por marcador
const parts = text.split("===ITEM===");
parts.shift();

const out = [];

for (const raw of parts) {
  const item = raw.trim();
  if (!item) continue;

  // tenta pegar o número real do item no início do bloco (ex.: "1 ITEM 1 - ...")
  const m = item.match(/^\s*(\d+)\s+/);
  const itemIndex = m ? m[1] : String(out.length + 1);

  // filtro mínimo: manter se tiver texto relevante
  if (item.length < 20) continue;

  out.push({
    json: {
      item_index: String(itemIndex),
      item_text: item,
    },
  });
}

return out;

const items = $input.all();

function cleanText(s) {
  return String(s || "")
    .replace(/\$/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function extractAcabamentosFallback(current, descricao) {
  const atual = cleanText(current || "");
  if (atual) return atual;

  const desc = String(descricao || "");

  const m = desc.match(
    /Acabamentos?:\s*(.+?)(?=(?:\.\s*Sendo:)|(?:\n\s*Sendo:)|(?:\.\s*\d+\s*$)|(?:\n)|$)/i
  );

  if (!m) return "";

  return cleanText(m[1]).replace(/[.;]+$/g, "").trim();
}

function normalizeMateriasPrimas(arr) {
  if (!Array.isArray(arr)) return [];

  const out = [];

  for (const raw of arr) {
    const nome = cleanText(raw?.nome || "");
    const especificacao = cleanText(raw?.especificacao || "");
    const unidade = cleanText(raw?.unidade || "");
    const quantidade = cleanText(raw?.quantidade || "");

    if (!nome && !especificacao && !unidade && quantidade) {
      if (out.length > 0) {
        out[out.length - 1].quantidade = out[out.length - 1].quantidade
          ? `${out[out.length - 1].quantidade} | ${quantidade}`
          : quantidade;
      }
      continue;
    }

    if (
      nome &&
      !especificacao &&
      !unidade &&
      !quantidade &&
      /^\d+(?:[.,]\d+)?\s*[A-Za-zÀ-ÿ]+$/i.test(nome)
    ) {
      if (out.length > 0) {
        out[out.length - 1].quantidade = out[out.length - 1].quantidade
          ? `${out[out.length - 1].quantidade} | ${nome}`
          : nome;
      }
      continue;
    }

    if (
      nome &&
      !especificacao &&
      !unidade &&
      quantidade &&
      /^(unid(?:ades)?|un|ml|m²|m2)$/i.test(nome)
    ) {
      const valorComUnidade = `${quantidade} ${nome}`.trim();
      if (out.length > 0) {
        out[out.length - 1].quantidade = out[out.length - 1].quantidade
          ? `${out[out.length - 1].quantidade} | ${valorComUnidade}`
          : valorComUnidade;
      }
      continue;
    }

    if (!nome && !especificacao && !unidade && !quantidade) continue;

    out.push({
      nome,
      especificacao,
      unidade,
      quantidade
    });
  }

  return out;
}

return items.map(item => {
  const meta = item.json || {};
  const data = meta.output?.[0]?.content?.[0]?.text || {};

  const descricaoFinal =
    cleanText(data.descricao_cliente || "") ||
    cleanText(meta.descricao_item_pai_raw || "");

  const acabamentosFinal = extractAcabamentosFallback(
    data.acabamentos,
    descricaoFinal
  );

  return {
    json: {
      ...data,

      item_index: meta.item_index ?? "",
      codigo_item_pai: meta.codigo_item_pai ?? "",
      subitem: meta.subitem ?? "",
      layout: meta.layout ?? "",
      linha_norm: meta.linha_norm ?? "",
      descricao_item_pai_raw: meta.descricao_item_pai_raw ?? "",

      descricao_cliente: descricaoFinal,
      produto: cleanText(data.produto || ""),
      modelo: cleanText(data.modelo || ""),
      acabamentos: acabamentosFinal,
      materias_primas: normalizeMateriasPrimas(data.materias_primas)
    }
  };
});

return items.map((it) => {
  const raw = (it.json.text ?? "").toString();

  let t = raw
    .replace(/\r\n/g, "\n")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  // Ref.: tudo entre "Ref." e "\nCliente"
  t = t.replace(/(\n?Ref\.\s*)([\s\S]*?)(\nCliente\b)/g, (m, p1, mid, p3) => {
    const ref = mid.replace(/\n+/g, " ").replace(/\s{2,}/g, " ").trim();
    return `\nRef. ${ref}${p3}`;
  });

  // Normalizar header "Cliente Contato Telefone"
  t = t.replace(/\nCliente\s+Contato\s+Telefone\s*\n?/g, "\nCliente Contato Telefone\n");

  // Juntar quebras dentro de parênteses
  t = (() => {
    let out = "";
    let depth = 0;
    for (let i = 0; i < t.length; i++) {
      const ch = t[i];
      if (ch === "(") depth++;
      if (ch === ")") depth = Math.max(0, depth - 1);
      out += (ch === "\n" && depth > 0) ? " " : ch;
    }
    return out.replace(/\s{2,}/g, " ");
  })();

  // --- SMART JOIN (principal) ---
  const anchors = [
    /^Ordem de serviço\b/i,
    /^Instalado\b/i,
    /^Entrega:\s*/i,
    /^Aprovação:\s*/i,
    /^Ref\.\s*/i,
    /^Cliente\s+Contato\s+Telefone\b/i,
    /^CNPJ\/CPF\s+Endereço\b/i,
    /^Processos de produção previstos\b/i,
    /^Observações da O\.S\.\b/i,
    /^OBS\.:/i,
    /^Item\s+Descrição/i,
    /^Imagem\s+Produto/i,
    /^Produto\s+Modelo/i,
    /^Matéria-?prima do item\b/i,
    /^Matéria\s+prima\s+Unid\s+Qtd\s+Uso\b/i,
    /^Tamanhos Item:\b/i,
    /^Autorizado por:\b/i,
  ];

  const isAnchor = (line) => {
    const s = line.trim();
    if (!s) return true;                 // mantém blocos
    if (/^\d+\/\d+$/.test(s)) return true; // "5/5"
    return anchors.some((re) => re.test(s));
  };

  let lines = t.split("\n").map(l => l.trimEnd());
  let out = [];

  for (let i = 0; i < lines.length; i++) {
    let cur = (lines[i] ?? "").trim();
    if (!cur) { out.push(""); continue; }

    let next = (lines[i + 1] ?? "").trim();

    // junta "Impressão" + "60.164 min"
    if (next && /^[\d.]+\s*min$/i.test(next) && !isAnchor(cur) && !isAnchor(next)) {
      out.push(`${cur} ${next}`);
      i++;
      continue;
    }

    // junta “Duque de” + “Caxias - RJ” (conectivos/virgula/hífen)
    if (next && /(?:\bde\b|\bda\b|\bdo\b|,|-)$/.test(cur.toLowerCase()) && !isAnchor(cur) && !isAnchor(next)) {
      out.push(`${cur} ${next}`);
      i++;
      continue;
    }

    // join genérico de wrap (não-âncora + próxima não-âncora)
    if (next && !isAnchor(cur) && !isAnchor(next)) {
      out.push(`${cur} ${next}`.replace(/\s{2,}/g, " "));
      i++;
      continue;
    }

    out.push(cur);
  }

  t = out.join("\n").replace(/\n{3,}/g, "\n\n").trim();

  it.json.os_txt = `<OS_TXT_INICIO>\n${t}\n<OS_TXT_FIM>`;
  return it;

  // Remove a coluna "Imagem" do header e dos dados (mantém o resto)
  t = t.replace(/^Imagem\s+Produto\s+Modelo/mg, "Produto Modelo");
  t = t.replace(/^Imagem\s+Produto\s+Modelo\s+Acabamentos/mg, "Produto Modelo Acabamentos");
});

return items.map((item) => {
  let text = item.json.text ?? '';
  const n = Number(item.json.numpages ?? 0) || 0;

  // normaliza quebras
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // 1) Remove rodapé "Autorizado por..." + paginação (somente páginas 1..n-1)
  // cobre os 2 formatos: "1/5\nAutorizado..." e "Autorizado... 1/5"
  if (n > 1) {
    for (let p = 1; p <= n - 1; p++) {
      const reA = new RegExp(
        String.raw`\n?\s*${p}\s*\/\s*${n}\s*\n\s*Autorizado\s+por:.*?(?:\n|$)`,
        'gi'
      );
      const reB = new RegExp(
        String.raw`\n\s*Autorizado\s+por:.*?\b${p}\s*\/\s*${n}\b.*?(?:\n|$)`,
        'gi'
      );
      text = text.replace(reA, '\n').replace(reB, '\n');
    }
  }

  // 2) Remove cabeçalho repetido (mantém o primeiro; remove os demais)
  // regra: cada header começa em "Ordem de serviço nº" e termina logo após a linha "Ref."
  // + opcionalmente 1 linha extra curta em CAIXA ALTA (ex: "SHOPPING")
  const headerToken = 'Ordem de serviço nº';
  const first = text.indexOf(headerToken);

  if (first !== -1) {
    let out = text.slice(0, first);        // antes do primeiro header (se existir)
    let rest = text.slice(first);          // do primeiro header em diante

    // mantém o primeiro header inteiro
    out += rest;
    // agora remove headers repetidos a partir do 2º
    let idx = out.indexOf('\n' + headerToken, first + headerToken.length);

    while (idx !== -1) {
      const start = idx + 1; // pula o \n
      // acha fim da linha "Ref."
      const refPos = out.indexOf('\nRef.', start);
      if (refPos === -1) break;

      const endRefLine = out.indexOf('\n', refPos + 1);
      if (endRefLine === -1) break;

      let cutEnd = endRefLine + 1;

      // linha opcional extra (ex "SHOPPING"), curta e em CAIXA ALTA
      const nextLineEnd = out.indexOf('\n', cutEnd);
      if (nextLineEnd !== -1) {
        const nextLine = out.slice(cutEnd, nextLineEnd).trim();
        if (
          nextLine.length > 0 &&
          nextLine.length <= 32 &&
          /^[A-Z0-9ÇÃÕÁÀÂÊÔÉÍÓÚÜ\-\/ ]+$/.test(nextLine)
        ) {
          cutEnd = nextLineEnd + 1;
        }
      }

      // remove o header repetido
      out = out.slice(0, start) + out.slice(cutEnd);

      idx = out.indexOf('\n' + headerToken, start);
    }

    text = out;
  }

  // 3) Limpeza de linhas vazias (equivalente ao seu \n\s*\n do Make)
  text = text.replace(/\n[ \t]*\n+/g, '\n').trim();

  item.json.text = text;
  return item;
});

const items = $input.all();

function clean(s) {
  return String(s || "").replace(/\s+/g, " ").trim();
}

function parseEtiquetasFromLLM(itemJson) {
  // caso o output do LLM venha no formato padrão OpenAI
  const llmObj = itemJson.output?.[0]?.content?.[0]?.text;
  if (llmObj && Array.isArray(llmObj.etiquetas)) {
    return [...new Set(llmObj.etiquetas.map(clean).filter(Boolean))];
  }

  // caso já venha simplificado/mesclado
  if (Array.isArray(itemJson.etiquetas)) {
    return [...new Set(itemJson.etiquetas.map(clean).filter(Boolean))];
  }

  return ["[sem etiqueta]"];
}

function parseMaquinario(itemJson) {
  const llmObj = itemJson.output?.[0]?.content?.[0]?.text;

  if (llmObj && Array.isArray(llmObj.maquinario_utilizado)) {
    return [...new Set(llmObj.maquinario_utilizado.map(clean).filter(Boolean))];
  }

  if (Array.isArray(itemJson.maquinario_utilizado)) {
    return [...new Set(itemJson.maquinario_utilizado.map(clean).filter(Boolean))];
  }

  return [];
}

function toInt(v) {
  const n = parseInt(String(v || "").replace(/[^\d-]/g, ""), 10);
  return Number.isFinite(n) ? n : 0;
}

function normalizeMateriasPrimas(arr) {
  if (!Array.isArray(arr)) return [];

  return arr.map(mp => ({
    nome: clean(mp?.nome),
    especificacao: clean(mp?.especificacao),
    unidade: clean(mp?.unidade),
    quantidade: clean(mp?.quantidade),
  }));
}

function buildDimensoes(d) {
  return {
    largura: clean(d?.largura),
    altura: clean(d?.altura),
    espessura: clean(d?.espessura),
  };
}

const produtos = items.map(({ json }) => {
  const etiquetas = parseEtiquetasFromLLM(json);
  const maquinario_utilizado = parseMaquinario(json);

  return {
    codigo_item: clean(json.codigo_item),
    codigo_item_pai: clean(json.codigo_item_pai),
    subitem: clean(json.subitem),
    layout: clean(json.layout),

    descricao_cliente: clean(json.descricao_cliente),
    produto: clean(json.produto),
    modelo: clean(json.modelo),
    acabamentos: clean(json.acabamentos),

    dimensoes: buildDimensoes(json.dimensoes),
    quantidade: clean(json.quantidade),

    materias_primas: normalizeMateriasPrimas(json.materias_primas),
    maquinario_utilizado,
    contexto_producao: clean(json.contexto_producao),

    etiquetas
  };
});

const contagemItens = produtos.map(p => ({
  codigo_item_pai: p.codigo_item_pai || p.codigo_item,
  subitem: p.subitem,
  produto: p.produto,
  quantidade: toInt(p.quantidade)
}));

const quantidadeTotalItens = contagemItens.reduce((acc, i) => acc + i.quantidade, 0);

return [{
  json: {
    Produtos: produtos,
    ContagemItens: contagemItens,
    QuantidadeTotalItens: quantidadeTotalItens
  }
}];

const inputItems = $input.all();
const out = [];

const isHeaderOnly = (s) =>
  /^\s*(Produto\s+Modelo\s+Acabamentos\s+Largura\s+Altura(?:\s+Espess\.)?\s+Qtd\.?|M[ií]dia\s+Equipamentos\s+Acabamentos\s+Largura\s+Altura\s+Qtd\.?)\s*$/i
    .test(String(s || "").trim());

function extractDescricaoItemPai(txt) {
  let t = String(txt || "").trim();

  // remove código inicial do item, ex.: "4 - " / "6 "
  t = t.replace(/^\s*\d+(?:\.\d+)?\s*[-–]?\s*/, "");

  // corta tudo a partir do primeiro cabeçalho de tabela principal
  const headerMatch = t.search(
    /(?:^|\n)\s*(Produto\s+Modelo\s+Acabamentos\s+Largura\s+Altura(?:\s+Espess\.)?\s+Qtd\.?|M[ií]dia\s+Equipamentos\s+Acabamentos\s+Largura\s+Altura\s+Qtd\.?)/i
  );

  if (headerMatch >= 0) {
    t = t.slice(0, headerMatch).trim();
  }

  // remove linha final puramente numérica/dimensional, ex.: "3.500 x 2.610 x 1"
  t = t.replace(/\n?\s*\d[\d.,]*(?:\s*[xX]\s*\d[\d.,]*){1,2}\s*$/i, "");

  // remove linha final de quantidade isolada, ex.: "1000" / "2"
  t = t.replace(/\n?\s*\d+\s*$/i, "");

  // normaliza espaços
  t = t.replace(/\s+/g, " ").trim();

  return t;
}

for (const it of inputItems) {
  const data = it.json || {};
  const txt = String(data.item_text || "");
  const parent = String(data.item_index ?? "").trim();

  const descricaoItemPaiRaw = extractDescricaoItemPai(txt);

  const hits = [];

  // Subitem em início de linha: x.y + texto (bloqueia "3.500 x ..." e similares)
  const reLine = /(^|\n)\s*(\d+\.\d{1,2})(?!\d)\s+(?![xX]\b)(?=[A-Za-zÀ-ÿ])/g;
  let m;
  while ((m = reLine.exec(txt)) !== null) {
    const idx = m.index + (m[1] ? m[1].length : 0);
    hits.push({ idx, code: m[2] });
  }

  // Subitem colado após cabeçalho do layout B (mesma linha)
  const reHeaderB =
    /(^|\n)\s*(M[ií]dia\s+Equipamentos\s+Acabamentos\s+Largura\s+Altura\s+Qtd\.?)\b[ \t]+(\d+\.\d{1,2})(?!\d)[ \t]+(?=[A-Za-zÀ-ÿ])/gi;
  while ((m = reHeaderB.exec(txt)) !== null) {
    const idx = m.index + (m[1] ? m[1].length : 0);
    hits.push({ idx, code: m[3] });
  }

  hits.sort((a, b) => a.idx - b.idx);

  // remove hits duplicados muito próximos
  const uniq = [];
  for (const h of hits) {
    const last = uniq[uniq.length - 1];
    if (!last) {
      uniq.push(h);
      continue;
    }
    if (last.code === h.code && (h.idx - last.idx) < 120) {
      continue;
    }
    uniq.push(h);
  }

  // sem subitens -> 1 item normal
  if (uniq.length === 0) {
    out.push({
      json: {
        ...data,
        codigo_item_pai: parent,
        subitem: "",
        item_text_sub: txt.trim(),
        descricao_item_pai_raw: descricaoItemPaiRaw,
      },
    });
    continue;
  }

  // com subitens -> explode
  for (let i = 0; i < uniq.length; i++) {
    let start = uniq[i].idx;
    const end = i + 1 < uniq.length ? uniq[i + 1].idx : txt.length;

    // se a linha anterior for cabeçalho, inclui junto do bloco
    const prevNL = txt.lastIndexOf("\n", start - 1);
    const prevPrevNL = prevNL > 0 ? txt.lastIndexOf("\n", prevNL - 1) : -1;
    const prevLine = txt.slice(prevPrevNL + 1, prevNL).trim();
    if (isHeaderOnly(prevLine)) start = prevPrevNL + 1;

    const block = txt.slice(start, end).trim();

    // ignora bloco lixo "só cabeçalho"
    if (isHeaderOnly(block)) continue;

    out.push({
      json: {
        ...data,
        codigo_item_pai: parent,
        subitem: uniq[i].code,
        item_text_sub: block,
        descricao_item_pai_raw: descricaoItemPaiRaw,
      },
    });
  }
}

return out;

const items = $input.all();
const out = [];

const HEADER_A =
  /Produto\s+Modelo\s+Acabamentos\s+Largura\s+Altura(?:\s+Espess\.)?\s+Qtd\.?/i;

function firstRowAfterHeader(t, headerRegex) {
  const m = t.match(headerRegex);
  if (!m) return "";
  const after = t.slice(m.index + m[0].length);
  const lines = after.split("\n").map(s => s.trim()).filter(Boolean);
  return lines[0] || "";
}

function stripTrailingNumericTokens(s) {
  const parts = String(s || "").trim().split(/\s+/);
  while (parts.length && /^[\d.,|]+$/.test(parts[parts.length - 1])) parts.pop();
  return parts.join(" ").trim();
}

function normLikeDB(s) {
  let x = String(s || "").trim();

  // remove prefixo subitem: "4.1 "
  x = x.replace(/^\d+\.\d+\s+/, "");

  // remove separadores "$" e "&"
  x = x.replace(/[&$]/g, " ");

  // remove acento, padroniza símbolos
  x = x.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  x = x.replace(/[×]/g, "x");
  x = x.replace(/\*/g, "");

  // remove separadores decimais/milhar ENTRE dígitos
  x = x.replace(/(?<=\d)[.,](?=\d)/g, "");

  // colapsa espaços
  x = x.replace(/\s+/g, " ").trim().toUpperCase();

  return x;
}

for (const it of items) {
  const j = it.json || {};
  const t = String(j.item_text_sub || "");
  const isA = HEADER_A.test(t);

  let keyRaw = "";
  let linhaNorm = "";

  if (isA) {
    const row = firstRowAfterHeader(t, HEADER_A);
    keyRaw = stripTrailingNumericTokens(row);
    linhaNorm = normLikeDB(keyRaw);
  }

  out.push({
    json: {
      item_index: j.item_index ?? "",
      item_text: j.item_text ?? "",
