const items = $input.all();
const out = [];

function collapse(s) {
  return String(s || "").replace(/\s+/g, " ").trim();
}

function extractFirstMaterialName(text) {
  const m = String(text || "").match(
    /Mat[ée]ria-prima do item[\s\S]*?(?:Mat[ée]ria prima\s+Unid\s+Qtd\s+Uso(?:\s+Mat[ée]ria prima\s+Unid\s+Qtd\s+Uso)?\s*)?([^\n(]+?)(?=\s*\(estoque pref\.:)/i
  );
  return m ? collapse(m[1]) : "";
}

for (const it of items) {
  const j = it.json || {};
  const layout = String(j.layout || "");
  const txt = String(j.item_text_llm || "");

  // Só atua no layout B
  if (layout !== "B") {
    out.push({ json: j });
    continue;
  }

  // 1) Pega o trecho entre o cabeçalho B e "Matéria-prima do item"
  const m = txt.match(
    /M[ií]dia\s+Equipamentos\s+Acabamentos\s+Largura\s+Altura\s+Qtd\.?\s*([\s\S]*?)\s*Mat[ée]ria-prima do item/i
  );

  let produto = "";
  let modelo = "";
  let acabamentos = "";

  if (m) {
    let row = collapse(m[1]);

    // remove prefixo tipo "4.2 "
    row = row.replace(/^\d+\.\d+\s+/, "");

    // 2) Extrai dimensões/quantidade da direita para a esquerda
    const right = row.match(/^(.*)\s+(\d[\d.,]*)\s+(\d[\d.,]*)\s+(\d+)\s*$/);

    if (right) {
      const leftText = collapse(right[1]);

      // 3) Detecta início do trecho de acabamentos/processo
      const proc = leftText.match(
        /\b[A-ZÀ-Ý][A-Za-zÀ-ÿ\s/]*?\s*-\s*\d+\s*(?:minutos?|horas?)(?:\s*\/\s*unidade|\s+por\s+unidade|\s+por\s+hora)?(?:\s*,\s*[A-ZÀ-Ý][A-Za-zÀ-ÿ\s/]*?\s*-\s*\d+\s*(?:minutos?|horas?)(?:\s*\/\s*unidade|\s+por\s+unidade|\s+por\s+hora)?)*\s*$/i
      );

      const firstMaterial = extractFirstMaterialName(txt);

      if (proc) {
        const procStart = proc.index;
        acabamentos = collapse(leftText.slice(procStart));
        const beforeProc = collapse(leftText.slice(0, procStart));

        if (firstMaterial && beforeProc.toUpperCase().startsWith(firstMaterial.toUpperCase())) {
          produto = firstMaterial;
          modelo = collapse(beforeProc.slice(firstMaterial.length));
        } else {
          produto = beforeProc;
          modelo = "";
        }
      } else {
        // fallback: se não achou processo, usa primeira matéria-prima como produto
        if (firstMaterial) {
          produto = firstMaterial;
          modelo = "";
        } else {
          produto = leftText;
          modelo = "";
        }
        acabamentos = "";
      }
    }
  }

  const prefix =
    produto || modelo || acabamentos
      ? `LAYOUT_B_MATCH: produto="${produto}" modelo="${modelo}" acabamentos="${acabamentos}"\n`
      : `LAYOUT_B_MATCH: NOT_FOUND\n`;

  out.push({
    json: {
      ...j,
      item_text_llm: prefix + txt
    }
  });
}

return out;

const items = $input.all();

function clean(s) {
  return String(s ?? "")
    .replace(/\s+/g, " ")
    .trim();
}

function buildDimensoes(d) {
  const largura = clean(d?.largura);
  const altura = clean(d?.altura);
  const espessura = clean(d?.espessura);

  const parts = [largura, altura];
  if (espessura) parts.push(espessura);

  return parts.filter(Boolean).join(" x ");
}

function buildMateriasPrimas(mps) {
  if (!Array.isArray(mps)) return [];

  return mps
    .map((mp, i) => {
      const nome = clean(mp?.nome);
      const unidade = clean(mp?.unidade);
      const quantidade = clean(mp?.quantidade);

      if (!nome && !unidade && !quantidade) return "";

      return [
        `- MP${i + 1}:`,
        nome ? `nome=${nome}` : "",
        unidade ? `unidade=${unidade}` : "",
        quantidade ? `quantidade=${quantidade}` : ""
      ]
        .filter(Boolean)
        .join(" | ");
    })
    .filter(Boolean);
}

return items.map(({ json }) => {
  const { output, ...base } = json;

  const codigoItem = clean(json.codigo_item);
  const codigoItemPai = clean(json.codigo_item_pai);
  const subitem = clean(json.subitem);
  const isSubitem = !!subitem;

  const descricaoCliente = clean(json.descricao_cliente);
  const descricaoPai = clean(json.descricao_item_pai_raw);

  const produto = clean(json.produto || json.produto_midia);
  const modelo = clean(json.modelo || json.modelo_equipamentos);
  const acabamentos = clean(json.acabamentos);
  const quantidade = clean(json.quantidade);
  const dimensoes = buildDimensoes(json.dimensoes);
  const contextoProducao = clean(json.contexto_producao);

  const materiasPrimas = buildMateriasPrimas(json.materias_primas);

  const textoEtiquetas = [
    `MODO_CLASSIFICACAO: ${isSubitem ? "SUBITEM" : "ITEM"}`,
    codigoItem ? `CODIGO_ITEM: ${codigoItem}` : "CODIGO_ITEM: ",
    codigoItemPai ? `CODIGO_ITEM_PAI: ${codigoItemPai}` : "CODIGO_ITEM_PAI: ",
    subitem ? `SUBITEM: ${subitem}` : "SUBITEM: ",
    `LAYOUT: ${clean(json.layout)}`,

    "",

    "SINAIS_DIRETOS_DO_ITEM:",
    produto ? `PRODUTO_MIDIA: ${produto}` : "PRODUTO_MIDIA: ",
    modelo ? `MODELO_EQUIPAMENTOS: ${modelo}` : "MODELO_EQUIPAMENTOS: ",
    acabamentos ? `ACABAMENTOS: ${acabamentos}` : "ACABAMENTOS: ",
    dimensoes ? `DIMENSOES: ${dimensoes}` : "DIMENSOES: ",
    quantidade ? `QUANTIDADE: ${quantidade}` : "QUANTIDADE: ",
    contextoProducao ? `CONTEXTO_PRODUCAO: ${contextoProducao}` : "CONTEXTO_PRODUCAO: ",

    "MATERIAS_PRIMAS:",
    ...(materiasPrimas.length ? materiasPrimas : ["-"]),

    "",
    "DESCRICAO_CLIENTE_CONTEXTO_FRACO:",
    descricaoCliente || "-",

    "",
    "CONTEXTO_ITEM_PAI_APENAS_REFERENCIA:",
    isSubitem
      ? (descricaoPai || "-")
      : "-",

    "",
    "REGRAS_APLICAVEIS:",
    "- Se SUBITEM estiver preenchido, nunca usar o item pai sozinho para ativar processo.",
    "- Priorizar sinais diretos do item: produto/mídia, modelo/equipamentos, acabamentos, matérias-primas e contexto_producao.",
    "- DESCRICAO_CLIENTE e CONTEXTO_ITEM_PAI_APENAS_REFERENCIA são contexto fraco.",
    "- Se houver conflito entre contexto geral e sinais diretos do subitem, os sinais diretos vencem."
  ].join("\n");

  return {
    json: {
      ...base,
      texto_etiquetas: textoEtiquetas
    }
  };
});

