function parseSinonimos(value) {
  if (!value) return [];

  if (Array.isArray(value)) {
    return value
      .map(v => String(v).trim())
      .filter(Boolean);
  }

  const s = String(value).trim();

  // caso venha como string tipo "{A,B,C}"
  if (s.startsWith('{') && s.endsWith('}')) {
    return s
      .slice(1, -1)
      .split(',')
      .map(v => v.trim().replace(/^"|"$/g, ''))
      .filter(Boolean);
  }

  // fallback simples
  return [s];
}

const rows = items
  .map(i => i.json)
  .filter(r => {
    if (r.ativo === true) return true;
    if (String(r.ativo).toLowerCase() === 'true') return true;
    return false;
  });

const base = rows.map(r => ({
  canonico: String(r.nome || '').trim(),
  sinonimos: parseSinonimos(r.sinonimos),
}));

return [
  {
    json: {
      oracle_hints_base: base
    }
  }
];

function normalize(str) {
  return String(str || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();
}

function uniqueByCanonico(arr) {
  const seen = new Set();
  const out = [];

  for (const row of arr) {
    const key = String(row.canonico || '').trim();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(row);
  }

  return out;
}

function titleCase(str) {
  return String(str || '')
    .toLowerCase()
    .replace(/\b\w/g, c => c.toUpperCase());
}

function inferDisplayName(canonico, sinonimos) {
  const c = String(canonico || '').trim();
  const sin = Array.isArray(sinonimos) ? sinonimos.map(s => String(s).trim()).filter(Boolean) : [];
  const all = [c, ...sin];
  const allNorm = all.map(normalize);

  if (allNorm.some(v => v.includes('IMPRESSORA PRISMAJET'))) return 'Impressora Prismajet';
  if (allNorm.some(v => v.includes('IMPRESSORA MIMAKI UV'))) return 'Impressora Mimaki UV';
  if (allNorm.some(v => v.includes('IMPRESSORA MUTOH SUBLIMATICA'))) return 'Impressora Mutoh Sublimática';
  if (allNorm.some(v => v.includes('IMPRESSORA KONICA 308'))) return 'Impressora Konica 308';
  if (allNorm.some(v => v.includes('CALANDRA'))) return 'Calandra';
  if (allNorm.some(v => v.includes('IECHO')) || allNorm.some(v => v.includes('I-ECHO'))) return 'Corte iECHO';
  if (allNorm.some(v => v.includes('REFILE NA MESA'))) return 'Refile na Mesa';
  if (allNorm.some(v => v.includes('MARCENARIA'))) return 'Marcenaria';
  if (allNorm.some(v => v.includes('PINTURA'))) return 'Pintura';
  if (allNorm.some(v => v.includes('SERRALHERIA'))) return 'Serralheria';

  const preferido = sin.find(s => /^IMPRESSORA\b/i.test(s)) || c || sin[0] || '';
  return titleCase(preferido);
}

function montarHintsRelevantes(textoItem, oracleBase) {
  const textoNorm = normalize(textoItem);

  const matched = oracleBase.filter(proc => {
    const canonicoNorm = normalize(proc.canonico);
    const sinonimosNorm = Array.isArray(proc.sinonimos)
      ? proc.sinonimos.map(normalize).filter(Boolean)
      : [];

    if (canonicoNorm && textoNorm.includes(canonicoNorm)) return true;
    return sinonimosNorm.some(s => s && textoNorm.includes(s));
  });

  return uniqueByCanonico(matched);
}

function montarBlocoOracle(hints) {
  if (!hints.length) {
    return 'ORACLE_PROCESSO_HINTS:\n- nenhum hint relevante encontrado';
  }

  const linhas = hints.map(h => {
    const canonico = String(h.canonico || '').trim();
    const display = String(h.display || '').trim();
    const sinonimos = Array.isArray(h.sinonimos) ? h.sinonimos : [];
    return `- canonico="${canonico}" display="${display}" sinonimos=${JSON.stringify(sinonimos)}`;
  });

  return `ORACLE_PROCESSO_HINTS:\n${linhas.join('\n')}`;
}

function inserirBlocoNoItemText(baseText, blocoOracle) {
  const text = String(baseText || '').trim();
  if (!text) return blocoOracle;

  const lines = text.split('\n');
  const primeira = String(lines[0] || '').trim();

  if (
    primeira.startsWith('CATALOGO_MATCH:') ||
    primeira.startsWith('LAYOUT_B_MATCH:')
  ) {
    return [
      primeira,
      blocoOracle,
      ...lines.slice(1),
    ].join('\n').trim();
  }

  return `${blocoOracle}\n${text}`.trim();
}

const itensOriginais = $('Preparar layout B').all();
const oracleBaseRaw = $('Montar base ORACLE hints').first().json.oracle_hints_base || [];

const oracleBase = oracleBaseRaw
  .map(row => {
    const canonico = String(row.canonico || '').trim();
    const sinonimos = Array.isArray(row.sinonimos)
      ? row.sinonimos.map(v => String(v).trim()).filter(Boolean)
      : [];

    return {
      canonico,
      sinonimos,
      display: inferDisplayName(canonico, sinonimos),
    };
  })
  .filter(row => row.canonico);

return itensOriginais.map(item => {
  const j = item.json;
  const textoBase = j.item_text_llm || j.item_text_sub || j.item_text || '';

  const hintsRelevantes = montarHintsRelevantes(textoBase, oracleBase);
  const blocoOracle = montarBlocoOracle(hintsRelevantes);
  const itemTextFinal = inserirBlocoNoItemText(textoBase, blocoOracle);

  return {
    json: {
      ...j,
      oracle_hints_injetados: hintsRelevantes,
      item_text_llm: itemTextFinal,
    },
  };
});
